     else if (enable)

before_code:
module counter_16bit(
  input clk,
  input rst_n,
  input enable,
  output reg [15:0] count
 );

  always @(posedge clk) begin
    if (!rst_n)
      count <= 16'h0000;
    else if (enable)
      count <= count + 1;
  end

endmodule

after_code:
module counter_16bit(
  input clk,
  input rst_n,
  input enable,
  output reg [15:0] count
 );

  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      count <= 16'h0000;
    else if (enable)
      count <= count + 1;
  end

endmodule
